// src/History.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function History({ employee }) {
  const navigate = useNavigate();
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [bills, setBills] = useState([]);

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const [tRes, kRes, bRes] = await Promise.all([
        fetch(
          `${apiBase}/travel-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(
          `${apiBase}/ticket-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(`${apiBase}/bills?empld=${encodeURIComponent(employee.empld)}`),
      ]);

      const [travel, tickets, billsData] = await Promise.all([
        tRes.json(),
        kRes.json(),
        bRes.json(),
      ]);

      setTravelExpenses(Array.isArray(travel) ? travel : []);
      setTicketExpenses(Array.isArray(tickets) ? tickets : []);
      setBills(Array.isArray(billsData) ? billsData : []);
    } catch (err) {
      console.error("History fetch error:", err);
      setTravelExpenses([]);
      setTicketExpenses([]);
      setBills([]);
    }
  };

  if (!employee) {
    return (
      <div style={centerScreen}>
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 20,
        fontFamily: "Segoe UI",
      }}
    >
      <div style={card}>
        {/* Back + title */}
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            onClick={() => navigate("/profile")}
            style={backBtn}
          >
            â¬… Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>History</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginTop: 6 }}>
          Employee: {employee.name} â€˘ {employee.empld}
        </p>

        {/* 3 blocks */}
        <div style={{ display: "flex", flexDirection: "column", gap: 18, marginTop: 10 }}>
          {/* Travel summary */}
          <section style={sectionBox}>
            <div style={sectionHeader}>
              <h3 style={sectionTitle}>Travel Expense History</h3>
              <button
                style={linkButton}
                onClick={() => navigate("/travel-history")}
              >
                View all &nbsp;â€ş
              </button>
            </div>

            <table style={tableStyle}>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Purpose</th>
                  <th>Amount</th>
                  <th>From</th>
                  <th>To</th>
                </tr>
              </thead>
              <tbody>
                {travelExpenses.slice(0, 5).map((t) => (
                  <tr key={t.id}>
                    <td>{t.travel_date?.split?.("T")?.[0] || t.travel_date}</td>
                    <td>{t.purpose}</td>
                    <td>â‚ą{t.amount}</td>
                    <td>{t.location_from || t.from}</td>
                    <td>{t.location_to || t.to}</td>
                  </tr>
                ))}
                {travelExpenses.length === 0 && (
                  <tr>
                    <td colSpan="5" style={emptyCell}>
                      No travel records yet.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </section>

          {/* Ticket summary */}
          <section style={sectionBox}>
            <div style={sectionHeader}>
              <h3 style={sectionTitle}>Ticket Expense History</h3>
              <button
                style={linkButton}
                onClick={() => navigate("/ticket-history")}
              >
                View all &nbsp;â€ş
              </button>
            </div>

            <table style={tableStyle}>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Purpose</th>
                  <th>Assigned To</th>
                  <th>Amount</th>
                </tr>
              </thead>
              <tbody>
                {ticketExpenses.slice(0, 5).map((t) => (
                  <tr key={t.id}>
                    <td>{t.ticket_date?.split?.("T")?.[0] || t.ticket_date}</td>
                    <td>{t.purpose}</td>
                    <td>{t.assigned_to}</td>
                    <td>â‚ą{t.amount}</td>
                  </tr>
                ))}
                {ticketExpenses.length === 0 && (
                  <tr>
                    <td colSpan="4" style={emptyCell}>
                      No ticket records yet.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </section>

          {/* Bills summary */}
          <section style={sectionBox}>
            <div style={sectionHeader}>
              <h3 style={sectionTitle}>Bills Upload History</h3>
              <button
                style={linkButton}
                onClick={() => navigate("/bills-history")}
              >
                View all &nbsp;â€ş
              </button>
            </div>

            <table style={tableStyle}>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>File Name</th>
                  <th>Preview</th>
                </tr>
              </thead>
              <tbody>
                {bills.slice(0, 5).map((b) => (
                  <tr key={b.id}>
                    <td>{b.created_at?.split?.("T")?.[0] || b.created_at}</td>
                    <td>{b.fileName || b.filename}</td>
                    <td>
                      {b.filePath && (
                        <a
                          href={`${apiBase}${b.filePath}`}
                          target="_blank"
                          rel="noreferrer"
                        >
                          Open
                        </a>
                      )}
                    </td>
                  </tr>
                ))}
                {bills.length === 0 && (
                  <tr>
                    <td colSpan="3" style={emptyCell}>
                      No bills uploaded yet.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </section>
        </div>
      </div>
    </div>
  );
}

